void VPInterleaveRecipe::execute(VPTransformState &State) {
  IRBuilder<> &Builder = State.Builder;
  auto *IG = cast<InterleaveGroup<Instruction>>(getInterleaveGroup());
  unsigned NumElts = IG->getFactor();

  // Allocate a vector for the whole group.
  auto *VecTy = FixedVectorType::get(IG->getMember(0)->getType(), NumElts);
  Value *UndefVec = UndefValue::get(VecTy);

  // Insert all members of the group.
  for (unsigned i = 0; i < NumElts; ++i) {
    Value *NewV = State.VPValue2Value[getOperand(i)];
    UndefVec = Builder.CreateInsertElement(UndefVec, NewV, i);
  }

  State.VPValue2Value[getVPValue()] = UndefVec;
}

