void VPBlendRecipe::execute(VPTransformState &State) {
  IRBuilder<> &Builder = State.Builder;
  auto *PN = cast<PHINode>(getUnderlyingValue());
  assert(PN->getNumIncomingValues() == 2 && "can only handle 2-way phis.");

  Value *V1 = State.VPValue2Value[getOperand(0)];
  Value *V2 = State.VPValue2Value[getOperand(1)];
  Value *Mask = State.VPValue2Value[getOperand(2)];

  assert(V1 && V2 && Mask && "Values not emitted for blend");
  Value *Sel = Builder.CreateSelect(Mask, V1, V2, "blend");
  State.VPValue2Value[getVPValue()] = Sel;
}

