void VPCanonicalIVPHIRecipe::execute(VPTransformState &State) {
  IRBuilder<> &Builder = State.Builder;
  Type *Ty = getUnderlyingValue()->getType();
  Value *Zero = ConstantInt::get(Ty, 0);
  Value *One = ConstantInt::get(Ty, 1);
  Value *Step = ConstantInt::get(Ty, State.VF.getKnownMinValue());

  // Create the canonical IV for the vector loop.
  PHINode *VecIV = Builder.CreatePHI(Ty, 2, "vec.iv");
  Value *NextIV = Builder.CreateAdd(VecIV, Step, "vec.iv.next");
  VecIV->addIncoming(Zero, State.CurrentVectorLoop->getLoopPreheader());
  VecIV->addIncoming(NextIV, State.CurrentVectorLoop->getLoopLatch());

  // Create the vector version of the canonical IV.
  Value *StartOffset = Builder.CreateVectorSplat(State.VF, Zero);
  Value *StepVector = Builder.CreateVectorSplat(State.VF, One);
  Value *RunningIV = Builder.CreateAdd(
      Builder.CreateVectorSplat(State.VF, VecIV),
      State.Builder.CreateStepVector(StepVector->getType(), State.VF),
      "running.iv");

  State.VPValue2Value[getVPValue()] = RunningIV;
  State.VPValue2Value[getVPValue()->getLiveInP()] = StartOffset;
  State.VPValue2Value[getVPValue()->getLiveOutP()] =
      Builder.CreateVectorSplat(State.VF, NextIV);
}

