void VPReplicateRecipe::execute(VPTransformState &State) {
  IRBuilder<> &Builder = State.Builder;
  assert(getOperand(0)->getDefiningRecipe() == nullptr &&
         "Replicated value must be loop-invariant");
  Value *V = getOperand(0)->getUnderlyingValue();
  assert(V && "Replicated value must have an underlying value");
  State.VPValue2Value[getVPValue()] =
      Builder.CreateVectorSplat(State.VF, V, V->getName() + ".splat");
}

