InstructionCost VPPartialReductionRecipe::computeCost(ElementCount VF,
                                                      VPCostContext &Ctx) const {
  VPRecipeBase *OpR = getOperand(0)->getDefiningRecipe();
  if (isa<VPReductionPHIRecipe>(OpR)) {
    Instruction *RedInst =
        cast<Instruction>(getVPValue()->getDefiningRecipe()->getUnderlyingValue());
    Type *Ty = RedInst->getType();
    InstructionCost Cost = getScalarCost(RedInst);
    if (getIngredient(0) && isa<VPWidenCastRecipe>(getIngredient(0)))
      Cost += Ctx.TTI.getCastInstrCost(Instruction::ZExt, Ty,
                                       getOperand(0)->getUnderlyingValue()->getType(),
                                       TTI::TCK_RecipThroughput, RedInst);
    auto HandleWiden = [&](VPRecipeBase *R) {
      if (auto *Widen = dyn_cast_or_null<VPWidenCastRecipe>(R))
        Cost += Widen->cost(VF, Ctx);
    };
    if (getNumIngredients() > 1)
      HandleWiden(getIngredient(1));
    return Cost;
  } else if (auto Widen = dyn_cast<VPWidenRecipe>(OpR)) {
    Instruction *RedInst =
        cast<Instruction>(getVPValue()->getDefiningRecipe()->getUnderlyingValue());
    return Widen->cost(VF, Ctx) + getScalarCost(RedInst);
  }
  return getScalarCost(
      cast<Instruction>(getVPValue()->getDefiningRecipe()->getUnderlyingValue()));
}

void VPPartialReductionRecipe::execute(VPTransformState &State) {
  IRBuilder<> &Builder = State.Builder;
  auto *RedInst = cast<Instruction>(getUnderlyingValue());
  Value *NextV = State.VPValue2Value[getOperand(0)];
  Value *NewRedInst = Builder.CreateBinOp(
      (Instruction::BinaryOps)RedInst->getOpcode(), NextV,
      State.VPValue2Value[getOperand(1)], RedInst->getName());
  State.VPValue2Value[getVPValue()] = NewRedInst;
}

void VPPartialReductionRecipe::print(raw_ostream &O, const Twine &Indent) const {
  O << Indent << "PARTIAL-REDUCTION " << getAsVPValue()->getName() << " ";
  printOperands(O);
  O << "\n";
}

void VPReductionPHIRecipe::execute(VPTransformState &State) {
  IRBuilder<> &Builder = State.Builder;
  auto *OrigPhi = cast<PHINode>(getUnderlyingValue());
  Value *StartV = getStartValue();
  Value *VectorStartV = Builder.CreateVectorSplat(State.VF, StartV);
  Value *ReducedV = State.VPValue2Value[getOperand(0)];
  Value *HReducedV = State.getHorizontalReduction(ReducedV, OrigPhi);
  State.VPValue2Value[getVPValue()] = HReducedV;
  State.VPValue2Value[getVPValue()->getLiveInP()] = VectorStartV;
  State.VPValue2Value[getVPValue()->getLiveOutP()] = ReducedV;
}

