void VPExpandSCEVRecipe::execute(VPTransformState &State) {
  IRBuilder<> &Builder = State.Builder;
  const SCEV *Expr = getSCEV();
  auto *Plan = getVPlan();
  auto &Ctx = Plan->getEntry().getContext();
  auto *CanonicalIV = Ctx.TheVP->getCanonicalIV();
  Value *IV = State.VPValue2Value[Plan->getVPValue(CanonicalIV)];
  assert(IV && "Canonical IV not generated");
  Value *Expanded = Ctx.SE->getSCEVExpand(Expr, IV, Builder, State.VF);
  State.VPValue2Value[getVPValue()] = Expanded;
}

