void VPRecipeBase::print(raw_ostream &O, const Twine &Indent) const {
  O << Indent << "EMIT " << getAsVPValue()->getName() << " = " << getRecipeName()
    << " ";
  printOperands(O);
  O << "\n";
}

void VPRecipeBase::printOperands(raw_ostream &O) const {
  if (operands().empty())
    return;

  O << "(";
  interleaveComma(operands(), O,
                  [&](VPValue *Op) { O << Op->getName(); });
  O << ")";
}

