void VPBranchOnMaskRecipe::execute(VPTransformState &State) {
  IRBuilder<> &Builder = State.Builder;
  assert(State.VPValue2Value.count(getOperand(0)) && "mask not set");
  Value *Cond = State.VPValue2Value[getOperand(0)];
  Builder.CreateCondBr(Cond, DestTrue, DestFalse);
}

