void VPBranchOnCountRecipe::execute(VPTransformState &State) {
  IRBuilder<> &Builder = State.Builder;
  Value *IV = State.Builder.CreateLoad(State.VF->getVectorTripCount()->getType(),
                                       State.VF->getVectorTripCount());
  Value *TC = State.Builder.CreateLoad(State.TripCount->getType(),
                                       State.TripCount);
  Value *Cond = Builder.CreateICmpULT(IV, TC);
  Builder.CreateCondBr(Cond, DestTrue, DestFalse);
}

