InstructionCost VPPartialReductionRecipe::computeCost(ElementCount VF,
                                                      VPCostContext &Ctx) const {
  VPRecipeBase *OpR = getOperand(0)->getDefiningRecipe();
  if (isa<VPReductionPHIRecipe>(OpR)) {
    Instruction *RedInst =
        cast<Instruction>(getVPValue()->getDefiningRecipe()->getUnderlyingValue());
    Type *Ty = RedInst->getType();
    InstructionCost Cost = getScalarCost(RedInst);
    if (getIngredient(0) && isa<VPWidenCastRecipe>(getIngredient(0)))
      Cost += Ctx.TTI.getCastInstrCost(Instruction::ZExt, Ty,
                                       getOperand(0)->getUnderlyingValue()->getType(),
                                       TTI::TCK_RecipThroughput, RedInst);
    auto HandleWiden = [&](VPRecipeBase *R) {
      if (auto *Widen = dyn_cast_or_null<VPWidenCastRecipe>(R))
        Cost += Widen->cost(VF, Ctx);
    };
    if (getNumIngredients() > 1)
      HandleWiden(getIngredient(1));
    return Cost;
  } else if (auto Widen = dyn_cast<VPWidenRecipe>(OpR)) {
    Instruction *RedInst =
        cast<Instruction>(getVPValue()->getDefiningRecipe()->getUnderlyingValue());
    return Widen->cost(VF, Ctx) + getScalarCost(RedInst);
  }
  return getScalarCost(
      cast<Instruction>(getVPValue()->getDefiningRecipe()->getUnderlyingValue()));
}

