void VPInstruction::execute(VPTransformState &State) {
  IRBuilder<> &Builder = State.Builder;
  // Some recipes may not have a VPValue, because they don't generate any value.
  if (getVPValue()) {
    assert(!State.Value2VPValue.count(getUnderlyingValue()) &&
           "Underlying value already has a VPValue");
    State.Value2VPValue[getUnderlyingValue()] = getVPValue();
  }

  Instruction *NewInst = Inst->clone();
  NewInst->setName(getUnderlyingValue()->getName());

  // Fix operands of new instruction.
  for (const auto &operand : enumerate(NewInst->operands())) {
    VPValue *VPV = getOperand(operand.index());
    Value *V = State.VPValue2Value[VPV];
    // Note: in order to support VPInstructions with phi-like behavior (e.g.
    // VPCanonicalIVPHIRecipe), we need to map their defining VPValues to the
    // incoming values of the new phi node, which are not available yet.
    // Such VPInstructions must override execute() to map their operands
    // appropriately.
    assert(V && "Operand not found in VPValue2Value map");
    NewInst->setOperand(operand.index(), V);
  }

  Builder.Insert(NewInst);
  if (getVPValue())
    State.VPValue2Value[getVPValue()] = NewInst;
}

